+#[test]
+fn jsonl_import_normalizes_mixed_case_known_status_and_issue_type() {
+    assert_mixed_case_known_value_round_trip(
+        "In_Progress",
+        "Bug",
+        Status::InProgress,
+        IssueType::Bug,
+        "mixedcase0",
+    );
+    assert_mixed_case_known_value_round_trip(
+        "INPROGRESS",
+        "FEATURE",
+        Status::InProgress,
+        IssueType::Feature,
+        "mixedcase1",
+    );
+    assert_mixed_case_known_value_round_trip(
+        "DRAFT",
+        "Question",
+        Status::Draft,
+        IssueType::Question,
+        "mixedcase2",
+    );
+    assert_mixed_case_known_value_round_trip(
+        "TOMBSTONE",
+        "Docs",
+        Status::Tombstone,
+        IssueType::Docs,
+        "mixedcase3",
+    );
+    assert_mixed_case_known_value_round_trip(
+        "PINNED",
+        "Task",
+        Status::Pinned,
+        IssueType::Task,
+        "mixedcase4",
+    );
+}
